package com.domatapp.feature.auth.data.datasource

import com.domatapp.core.remote.annotations.Body
import com.domatapp.core.remote.annotations.POST
import com.domatapp.core.remote.annotations.Query
import com.domatapp.core.remote.annotations.RemoteDataSource
import com.domatapp.feature.auth.data.remote.AuthSessionRemoteModel
import com.domatapp.feature.auth.data.remote.GoogleSignInRemoteModel

/**
 * Remote data source for authentication via Supabase.
 * Implementation is automatically generated by KSP.
 */
@RemoteDataSource
interface AuthRemoteDataSource {

    /**
     * Sign in with Google ID token via Supabase auth endpoint.
     */
    @POST("auth/v1/token")
    suspend fun signInWithIdToken(
        @Query("grant_type") grantType: String,
        @Body body: GoogleSignInRemoteModel
    ): AuthSessionRemoteModel

    /**
     * Logout current user.
     */
    @POST("auth/v1/logout")
    suspend fun logout()
}
